601	fn f_gc(state: &mut LuaState) -> Result<usize, LuaError> {
602	    // C: if (!isclosed(p) && p->f != NULL) aux_close(L);  /* ignore errors */
603	    let p_rc = get_lstream(state)?;
604	    let needs_close = {
605	        let p = p_rc.borrow();
606	        !p.is_closed() && p.file.is_some()
607	    };
608	    if needs_close {
609	        // ignore any error from aux_close during GC finalisation
610	        let _ = aux_close(state);
611	    }
612	    Ok(0)
