751	/// Read and push a Lua number from `file`. Return `true` on success.
752	/// C: `read_number(L, f)`.
753	fn read_number(
754	    state: &mut LuaState,
755	    file: &mut dyn LuaFileHandle,
756	) -> Result<bool, LuaError> {
757	    // C: do { rn.c = l_getc(rn.f); } while (isspace(rn.c)); /* skip spaces */
758	    let first = loop {
759	        let b = file.read_byte();
760	        if b == EOF_SENTINEL || !(b as u8).is_ascii_whitespace() {
761	            break b;
762	        }
763	    };
764	
765	    let mut rn = ReadNumState::new(first);
766	
767	    // C: test2(&rn, "-+")
768	    rn.try2(file, [b'-', b'+']);
769	
770	    // C: if (test2(&rn, "00")) { if (test2(&rn, "xX")) hex = 1; else count = 1; }
771	    let mut count: usize = 0;
772	    let hex = if rn.try2(file, [b'0', b'0']) {
773	        if rn.try2(file, [b'x', b'X']) {
774	            true
775	        } else {
776	            count = 1;
777	            false
778	        }
779	    } else {
780	        false
781	    };
782	
783	    // C: count += readdigits(&rn, hex);
784	    count += rn.read_digits(file, hex);
785	
786	    // C: decp[0] = lua_getlocaledecpoint(); decp[1] = '.';
787	    // TODO(port): locale decimal-point character; defaulting to '.'
788	    let dec_point = b'.';
789	    if rn.try2(file, [dec_point, b'.']) {
790	        count += rn.read_digits(file, hex);
791	    }
792	
793	    // C: if (count > 0 && test2(&rn, hex ? "pP" : "eE")) { ... exponent ... }
794	    if count > 0 {
795	        let exp_chars = if hex { [b'p', b'P'] } else { [b'e', b'E'] };
796	        if rn.try2(file, exp_chars) {
797	            rn.try2(file, [b'-', b'+']);
798	            rn.read_digits(file, false);
799	        }
800	    }
801	
802	    // C: ungetc(rn.c, rn.f);
803	    file.unread_byte(rn.current);
804	
805	    // C: if (lua_stringtonumber(L, rn.buff)) return 1; else { lua_pushnil(L); return 0; }
806	    // TODO(port): state.string_to_number(bytes) — parses bytes into LuaValue::Int or Float
807	    let bytes = rn.as_bytes();
808	    let pushed = state.string_to_number_push(&bytes)?;
809	    if pushed != 0 {
810	        Ok(true)
811	    } else {
812	        state.push(LuaValue::Nil);
813	        Ok(false)
814	    }
815	}
