817	/// Test for EOF: push `""` and return `true` if not at EOF. C: `test_eof`.
818	fn test_eof(
819	    state: &mut LuaState,
820	    file: &mut dyn LuaFileHandle,
821	) -> Result<bool, LuaError> {
822	    // C: int c = getc(f); ungetc(c, f); lua_pushliteral(L, ""); return (c != EOF);
823	    let c = file.read_byte();
824	    if c != EOF_SENTINEL {
825	        file.unread_byte(c);
826	    }
827	    state.push_string(b"");
828	    Ok(c != EOF_SENTINEL)
829	}
