831	/// Read one line from `file` and push it. If `chop`, strip the trailing `\n`.
832	/// Return `true` if anything was read. C: `read_line(L, f, chop)`.
833	///
834	/// PERF(port): C uses luaL_prepbuffer (large fixed stack buffer) to avoid
835	/// per-byte allocation; Rust's Vec grows here, which is slightly slower.
836	fn read_line(
837	    state: &mut LuaState,
838	    file: &mut dyn LuaFileHandle,
839	    chop: bool,
840	) -> Result<bool, LuaError> {
841	    let mut buf: Vec<u8> = Vec::new();
842	    let mut c: i32 = EOF_SENTINEL;
843	
844	    // C: do { char *buff = luaL_prepbuffer(&b); int i = 0;
845	    //          while (i < LUAL_BUFFERSIZE && (c = l_getc(f)) != EOF && c != '\n')
846	    //            buff[i++] = c;
847	    //          luaL_addsize(&b, i);
848	    //    } while (c != EOF && c != '\n');
849	    'outer: loop {
850	        for _ in 0..LUAL_BUFFER_SIZE {
851	            c = file.read_byte();
852	            if c == EOF_SENTINEL || c == b'\n' as i32 {
853	                break 'outer;
854	            }
855	            buf.push(c as u8);
856	        }
857	        // chunk full but no newline/EOF yet — continue reading
858	    }
859	
860	    // C: if (!chop && c == '\n') luaL_addchar(&b, c);
861	    if !chop && c == b'\n' as i32 {
862	        buf.push(b'\n');
863	    }
864	
865	    // C: return (c == '\n' || lua_rawlen(L, -1) > 0);
866	    let had_content = c == b'\n' as i32 || !buf.is_empty();
867	    state.push_string(&buf);
868	    Ok(had_content)
869	}
