871	/// Read the entire file into a single string and push it. C: `read_all(L, f)`.
872	///
873	/// PERF(port): C uses `fread` with a large buffer; Rust reads byte-by-byte via
874	/// `LuaFileOps::read_byte`. Phase B should add `read_chunk(&mut buf)` to the
875	/// trait for bulk reads.
876	fn read_all(state: &mut LuaState, file: &mut dyn LuaFileHandle) -> Result<(), LuaError> {
877	    // C: do { nr = fread(p, LUAL_BUFFERSIZE, f); luaL_addsize(&b, nr); } while (nr == LUAL_BUFFERSIZE);
878	    let mut buf: Vec<u8> = Vec::new();
879	    loop {
880	        let start = buf.len();
881	        let mut chunk_read = 0usize;
882	        for _ in 0..LUAL_BUFFER_SIZE {
883	            let b = file.read_byte();
884	            if b == EOF_SENTINEL {
885	                break;
886	            }
887	            buf.push(b as u8);
888	            chunk_read += 1;
889	        }
890	        if chunk_read < LUAL_BUFFER_SIZE {
891	            break;
892	        }
893	    }
894	    state.push_string(&buf);
895	    Ok(())
896	}
