898	/// Read exactly `n` bytes from `file` and push the result.
899	/// Return `true` if anything was read. C: `read_chars(L, f, n)`.
900	fn read_chars(
901	    state: &mut LuaState,
902	    file: &mut dyn LuaFileHandle,
903	    n: usize,
904	) -> Result<bool, LuaError> {
905	    // C: nr = fread(p, sizeof(char), n, f); luaL_addsize(&b, nr); return (nr > 0);
906	    let mut buf = Vec::with_capacity(n);
907	    for _ in 0..n {
908	        let b = file.read_byte();
909	        if b == EOF_SENTINEL {
910	            break;
911	        }
912	        buf.push(b as u8);
913	    }
914	    let nr = buf.len();
915	    state.push_string(&buf);
916	    Ok(nr > 0)
917	}
