919	/// Dispatch one or more read formats; push results. C: `g_read(L, f, first)`.
920	///
921	/// TODO(port): borrow split — `file` is `&mut dyn LuaFileOps` extracted from a
922	/// `LuaUserData` that lives inside `state`. Phase B must restructure so the file
923	/// is accessed through the stack index rather than a raw borrow.
924	fn g_read(
925	    state: &mut LuaState,
926	    file: &mut dyn LuaFileHandle,
927	    first: i32,
928	) -> Result<usize, LuaError> {
929	    // C: int nargs = lua_gettop(L) - 1;
930	    let nargs = state.top_idx().get() as i32 - 1;
931	    let mut n = first;
932	    let mut success = true;
933	
934	    // C: clearerr(f);
935	    file.clear_error();
936	
937	    if nargs == 0 {
938	        // C: success = read_line(L, f, 1); n = first + 1;
939	        success = read_line(state, file, true)?;
940	        n = first + 1;
941	    } else {
942	        // C: luaL_checkstack(L, nargs+LUA_MINSTACK, "too many arguments");
943	        state.ensure_stack((nargs as i32) + 20, "too many arguments")?;
944	        let mut remaining = nargs;
945	        while remaining > 0 && success {
946	            // C: if (lua_type(L, n) == LUA_TNUMBER)
947	            if state.type_at(n) == LuaType::Number {
948	                // C: size_t l = (size_t)luaL_checkinteger(L, n);
949	                let l = state.check_arg_integer(n)? as usize;
950	                success = if l == 0 {
951	                    test_eof(state, file)?
952	                } else {
953	                    read_chars(state, file, l)?
954	                };
955	            } else {
956	                // C: const char *p = luaL_checkstring(L, n);
957	                // C: if (*p == '*') p++;  /* skip optional '*' (compat) */
958	                let s: Vec<u8> = state.check_arg_string(n)?;
959	                let p: &[u8] = if s.first() == Some(&b'*') { &s[1..] } else { &s[..] };
960	                match p.first() {
961	                    // C: case 'n': success = read_number(L, f); break;
962	                    Some(&b'n') => {
963	                        success = read_number(state, file)?;
964	                    }
965	                    // C: case 'l': success = read_line(L, f, 1); break;
966	                    Some(&b'l') => {
967	                        success = read_line(state, file, true)?;
968	                    }
969	                    // C: case 'L': success = read_line(L, f, 0); break;
970	                    Some(&b'L') => {
971	                        success = read_line(state, file, false)?;
972	                    }
973	                    // C: case 'a': read_all(L, f); success = 1; break;
974	                    Some(&b'a') => {
975	                        read_all(state, file)?;
976	                        success = true;
977	                    }
978	                    _ => {
979	                        return Err(LuaError::arg_error(n, "invalid format"));
980	                    }
981	                }
982	            }
983	            n += 1;
984	            remaining -= 1;
985	        }
986	    }
987	
988	    // C: if (ferror(f)) return luaL_fileresult(L, 0, NULL);
989	    if file.has_error() {
990	        return file_result(
991	            state,
992	            false,
993	            None,
994	            io::Error::new(io::ErrorKind::Other, "file read error"),
995	        );
996	    }
997	
998	    // C: if (!success) { lua_pop(L, 1); luaL_pushfail(L); }
999	    if !success {
1000	        state.pop_n(1);
1001	        state.push(LuaValue::Bool(false));
1002	    }
1003	
1004	    // C: return n - first;
1005	    Ok((n - first) as usize)
1006	}
