1037	    // C: int nargs = lua_gettop(L) - arg;
1038	    let nargs = state.top_idx().get() as i32 - arg;
1039	    let mut overall_ok = true;
1040	
1041	    for i in 0..nargs {
1042	        let idx = arg + i;
1043	        if state.type_at(idx) == LuaType::Number {
1044	            // C: lua_isinteger(L, arg) ? fprintf(LUA_INTEGER_FMT,...) : fprintf(LUA_NUMBER_FMT,...)
1045	            // C: LUA_INTEGER_FMT = "%lld" (i64)
1046	            // C: LUA_NUMBER_FMT  = "%.14g" (f64, 14 significant digits)
1047	            // PERF(port): byte-by-byte write; Phase B add bulk write_fmt to LuaFileOps.
1048	            // TODO(port): C's %.14g (significant digits) has no direct Rust equivalent.
1049	            let s = if state.is_integer(idx) {
1050	                let ival = state.to_integer(idx).unwrap_or(0);
1051	                // C: LUA_INTEGER_FMT = "%lld"
1052	                format!("{}", ival)
1053	            } else {
1054	                let fval = state.to_number(idx).unwrap_or(0.0);
1055	                // C: LUA_NUMBER_FMT = "%.14g" — significant-digit format
1056	                // TODO(port): implement proper %.14g (choose between %e and %f based on magnitude)
1057	                format!("{:.14e}", fval)
1058	            };
1059	            match file.write_bytes(s.as_bytes()) {
1060	                Ok(n) => overall_ok = overall_ok && n == s.len(),
1061	                Err(_) => overall_ok = false,
1062	            }
1063	        } else {
1064	            // C: const char *s = luaL_checklstring(L, arg, &l);
1065	            // C: status = status && (fwrite(s, sizeof(char), l, f) == l);
1066	            let s: Vec<u8> = state.check_arg_string(idx)?;
1067	            match file.write_bytes(&s) {
1068	                Ok(n) => overall_ok = overall_ok && n == s.len(),
1069	                Err(_) => overall_ok = false,
1070	            }
1071	        }
1072	    }
1073	
1074	    // C: if (status) return 1; else return luaL_fileresult(L, status, NULL);
1075	    if overall_ok {
1076	        Ok(1) // file handle already at stack top; C returns it on success
1077	    } else {
1078	        file_result(
1079	            state,
1080	            false,
1081	            None,
1082	            io::Error::new(io::ErrorKind::Other, "write error"),
1083	        )
1084	    }
1085	}
