1087	/// `io.write(...)`. C: `io_write`.
1088	///
1089	/// Writes all arguments to the current default output file (`IO_OUTPUT`). When
1090	/// a file was set via `io.output(filename)`, writes go to that file; otherwise
1091	/// they go to stdout via `state.write_output()`.
1092	///
1093	/// The borrow split (needing both `&mut LuaState` and `&mut dyn LuaFileHandle`)
1094	/// is resolved by collecting all formatted strings first and then writing them
1095	/// to the file handle obtained from the `LSTREAM_REGISTRY`.
1096	pub fn io_write(state: &mut LuaState) -> Result<usize, LuaError> {
1097	    // C: g_write(L, getiofile(L, IO_OUTPUT), 1)
1098	    // Step 1: collect all formatted byte strings before touching the file handle.
1099	    let n = state.top();
1100	    let mut chunks: Vec<Vec<u8>> = Vec::with_capacity(n as usize);
1101	    for i in 1..=(n as i32) {
1102	        if state.type_at(i) == LuaType::Number {
1103	            let s = if state.is_integer(i) {
1104	                let ival = state.to_integer(i).unwrap_or(0);
1105	                // C: LUA_INTEGER_FMT = "%lld"
1106	                format!("{}", ival).into_bytes()
1107	            } else {
1108	                let fval = state.to_number(i).unwrap_or(0.0);
1109	                // TODO(port): proper %.14g (significant-digit) formatting.
1110	                format!("{:.14e}", fval).into_bytes()
1111	            };
1112	            chunks.push(s);
1113	        } else {
1114	            let bytes: Vec<u8> = state.check_arg_string(i)?;
1115	            chunks.push(bytes);
1116	        }
1117	    }
1118	
1119	    // Step 2: get the current output file handle from LSTREAM_REGISTRY if possible.
1120	    // Push the IO_OUTPUT userdata to the stack to read its identity, then pop it.
1121	    // The metatable check also verifies this is a live (not collected) file handle.
1122	    let ud_id: Option<usize> = {
1123	        state.registry_get(IO_OUTPUT_KEY)?;
1124	        let id = state.test_arg_userdata(-1, LUA_FILE_HANDLE)
1125	            .map(|ud| ud.identity());
1126	        state.pop_n(1);
1127	        id
1128	    };
1129	
1130	    if let Some(id) = ud_id {
1131	        if let Some(rc) = lookup_lstream(id) {
1132	            let mut p = rc.borrow_mut();
1133	            if let Some(fh) = p.file.as_mut() {
1134	                for chunk in &chunks {
1135	                    fh.write_bytes(chunk).map_err(|e| {
1136	                        LuaError::runtime(format_args!("io.write: {}", e))
1137	                    })?;
1138	                }
1139	                drop(p);
1140	                state.registry_get(IO_OUTPUT_KEY)?;
1141	                return Ok(1);
1142	            }
1143	        }
1144	    }
1145	
1146	    // Fallback: IO_OUTPUT is not a live file handle; write to the VM stdout sink.
1147	    for chunk in &chunks {
1148	        state.write_output(chunk)?;
1149	    }
1150	    state.registry_get(IO_OUTPUT_KEY)?;
1151	    Ok(1)
1152	}
