1244	/// Build the `io_readline` closure with its upvalues and push it.
1245	/// C: `aux_lines(L, toclose)`.
1246	///
1247	/// Upvalue layout (C comment):
1248	///   1) file handle (first stack value)
1249	///   2) number of read-format arguments
1250	///   3) toclose flag (bool)
1251	///   4..n+3) format arguments
1252	fn aux_lines(state: &mut LuaState, toclose: bool) -> Result<(), LuaError> {
1253	    // C: int n = lua_gettop(L) - 1;
1254	    let n = state.top_idx().get() as i32 - 1;
1255	    // C: luaL_argcheck(L, n <= MAXARGLINE, MAXARGLINE+2, "too many arguments");
1256	    if n > MAX_ARG_LINE as i32 {
1257	        return Err(LuaError::arg_error(
1258	            MAX_ARG_LINE as i32 + 2,
1259	            "too many arguments",
1260	        ));
1261	    }
1262	    // C: lua_pushvalue(L, 1);
1263	    state.push_value_at(1);
