1326	fn io_readline(state: &mut LuaState) -> Result<usize, LuaError> {
1327	    // C: LStream *p = (LStream *)lua_touserdata(L, lua_upvalueindex(1));
1328	    // C: int n = (int)lua_tointeger(L, lua_upvalueindex(2));
1329	    // TODO(port): access upvalues via state.get_upvalue(n); extract LStream from upvalue 1.
1330	    let n = match state.value_at(crate::state_stub::upvalue_index(2)) {
1331	        LuaValue::Int(i) => i as usize,
1332	        _ => 0,
