1343	    state.set_top(1);
1344	    // C: luaL_checkstack(L, n, "too many arguments");
1345	    state.ensure_stack(n as i32, "too many arguments")?;
1346	
1347	    // C: for (i = 1; i <= n; i++) lua_pushvalue(L, lua_upvalueindex(3 + i));
1348	    for i in 1..=n {
1349	        let uv = state.value_at(crate::state_stub::upvalue_index(3 + i as i32));
1350	        state.push(uv);
1351	    }
1352	
1353	    // C: n = g_read(L, p->f, 2);
1354	    // TODO(port): extract file from upvalue 1 LStream, call g_read(state, file, 2)
1355	    let result_n: usize = todo!("TODO(port): call g_read with file from upvalue 1");
1356	
1357	    // C: lua_assert(n > 0);
1358	    debug_assert!(result_n > 0, "g_read should return at least one value");
1359	
1360	    // C: if (lua_toboolean(L, -n)) return n;  /* read at least one value */
1361	    let top = state.top_idx().get() as i32;
1362	    let first_result_idx = top - result_n as i32;
1363	    let first_truthy = !matches!(
1364	        state.stack_at(first_result_idx),
1365	        LuaValue::Nil | LuaValue::Bool(false)
1366	    );
